/**
 * Telegram Mini App (TMA) Integration Service
 * Handles user data extraction and WebApp environment setup.
 */

export interface TelegramUser {
  id: number;
  first_name: string;
  last_name?: string;
  username?: string;
  language_code?: string;
  is_premium?: boolean;
}

export const getTelegramWebApp = () => {
  return (window as any).Telegram?.WebApp;
};

export const isTelegramEnvironment = () => {
  const tg = getTelegramWebApp();
  return !!(tg && tg.initData);
};

export const getTelegramUser = (): TelegramUser | null => {
  const tg = getTelegramWebApp();
  if (!tg) return null;

  // initDataUnsafe is populated when running inside Telegram
  return tg.initDataUnsafe?.user || null;
};

export const initTelegramTheme = () => {
  const tg = getTelegramWebApp();
  if (!tg) return;

  tg.ready();
  tg.expand();

  // Set the header color to match our Lexicon aesthetic
  tg.setHeaderColor('#fcfcfb');
  tg.setBackgroundColor('#fcfcfb');
};

export const triggerHaptic = (style: 'light' | 'medium' | 'heavy' | 'success' | 'warning' | 'error' = 'light') => {
  const tg = getTelegramWebApp();
  if (!tg?.HapticFeedback) return;

  if (['success', 'warning', 'error'].includes(style)) {
    tg.HapticFeedback.notificationOccurred(style);
  } else {
    tg.HapticFeedback.impactOccurred(style);
  }
};

