const supabaseUrl = 'https://pfykbgifzgfgeuiadebm.supabase.co';
const supabaseAnonKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InBmeWtiZ2lmemdmZ2V1aWFkZWJtIiwicm9sZSI6ImFub24iLCJpYXQiOjE3Njc0NTY5ODMsImV4cCI6MjA4MzAzMjk4M30.tSh8OgqVw3yk4JgCs7jzz21SJLKaotce_8AVAJdi9Z0';

export const supabase = createClient(supabaseUrl, supabaseAnonKey);

const missingTables = new Set<string>();

const handleSupabaseError = (error: any, tableName: string) => {
  if (error?.code === 'PGRST204' || error?.code === 'PGRST205' || error?.status === 404 || error?.message?.includes('does not exist')) {
    if (!missingTables.has(tableName)) {
      console.warn(`Supabase Table '${tableName}' not found or schema mismatch.`);
      missingTables.add(tableName);
    }
    return true;
  }
  return false;
};

export async function fetchSuggestions(query: string, sourceLang: Language): Promise<string[]> {
  if (missingTables.has('lex_entries') || query.length < 2) return [];
  try {
    const cleanQuery = query.toLowerCase().trim();
    const { data, error } = await supabase
      .from('lex_entries')
      .select('term')
      .eq('source_lang', sourceLang)
      .ilike('normalized_term', `${cleanQuery}%`)
      .limit(10);

    if (error) {
      handleSupabaseError(error, 'lex_entries');
      return [];
    }

    const results = data?.map(d => d.term).filter(Boolean) || [];
    return Array.from(new Set(results));
  } catch (err) {
    return [];
  }
}

export async function fetchGlobalEntry(
  normalizedTerm: string,
  sourceLang: Language,
  targetLang: Language
): Promise<LexicalEntry | null> {
  if (missingTables.has('lex_entries')) return null;
  try {
    const { data, error } = await supabase
      .from('lex_entries')
      .select('entry_data')
      .eq('normalized_term', normalizedTerm)
      .eq('source_lang', sourceLang)
      .eq('target_lang', targetLang)
      .maybeSingle();

    if (error) {
      handleSupabaseError(error, 'lex_entries');
      return null;
    }
    return data?.entry_data as LexicalEntry || null;
  } catch {
    return null;
  }
}

export async function saveGlobalEntry(entry: LexicalEntry) {
  if (missingTables.has('lex_entries')) return;
  try {
    await supabase
      .from('lex_entries')
      .upsert({
        term: entry.term,
        normalized_term: entry.normalizedTerm,
        source_lang: entry.sourceLang,
        target_lang: entry.targetLang,
        entry_data: entry
      }, { onConflict: 'normalized_term, source_lang, target_lang' });
  } catch {}
}

/** 
 * Fetches user profile using Telegram ID to enable cross-device sync 
 */
export async function fetchProfileByTelegramId(telegramId: number): Promise<UserProfile | null> {
  if (missingTables.has('lex_profiles')) return null;
  try {
    const { data, error } = await supabase
      .from('lex_profiles')
      .select('profile_data')
      .eq('telegram_id', telegramId)
      .maybeSingle();

    if (error) {
      handleSupabaseError(error, 'lex_profiles');
      return null;
    }
    return data?.profile_data as UserProfile || null;
  } catch {
    return null;
  }
}

export async function fetchUserHistory(telegramId: number): Promise<LexicalEntry[]> {
  if (missingTables.has('lex_user_history')) return [];
  try {
    const { data, error } = await supabase
      .from('lex_user_history')
      .select('entry_data')
      .eq('telegram_id', telegramId)
      .order('created_at', { ascending: false })
      .limit(50);

    if (error) {
      handleSupabaseError(error, 'lex_user_history');
      return [];
    }
    return data?.map(d => d.entry_data as LexicalEntry) || [];
  } catch {
    return [];
  }
}

export async function saveUserHistoryEntry(telegramId: number, entry: LexicalEntry) {
  if (missingTables.has('lex_user_history')) return;
  try {
    await supabase
      .from('lex_user_history')
      .upsert({
        telegram_id: telegramId,
        entry_id: entry.id,
        entry_data: entry,
        created_at: new Date().toISOString()
      }, { onConflict: 'telegram_id, entry_id' });
  } catch (err) {
    handleSupabaseError(err, 'lex_user_history');
  }
}

export async function fetchProfile(deviceId: string): Promise<UserProfile | null> {
  if (missingTables.has('lex_profiles')) return null;
  try {
    const { data, error } = await supabase
      .from('lex_profiles')
      .select('profile_data')
      .eq('device_id', deviceId)
      .maybeSingle();

    if (error) {
      handleSupabaseError(error, 'lex_profiles');
      return null;
    }
    return data?.profile_data as UserProfile || null;
  } catch {
    return null;
  }
}

export async function upsertProfile(deviceId: string, profile: UserProfile) {
  if (missingTables.has('lex_profiles')) return;
  try {
    // If we have a telegram ID, we must ensure it is saved in the column for foreign key support
    await supabase
      .from('lex_profiles')
      .upsert({ 
        device_id: deviceId, 
        profile_data: profile,
        telegram_id: profile.telegramId,
        username: profile.username,
        updated_at: new Date().toISOString() 
      }, { onConflict: 'device_id' });
  } catch (err) {
    handleSupabaseError(err, 'lex_profiles');
  }
}

import React, { useState, useEffect, useCallback } from 'react';
import { AppMode, LexicalEntry, UserProfile } from './types';
import Dictionary from './components/Dictionary';
import Arena from './components/Arena';
import Archive from './components/Archive';
import { RANKS } from './constants';
import { 
  fetchProfile, 
  upsertProfile, 
  fetchUserHistory, 
  saveUserHistoryEntry, 
  fetchProfileByTelegramId 
} from './services/supabase';
import { getTelegramUser, initTelegramTheme, isTelegramEnvironment } from './services/telegram';

const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>(AppMode.DICTIONARY);
  const [history, setHistory] = useState<LexicalEntry[]>([]);
  const [activeEntry, setActiveEntry] = useState<LexicalEntry | null>(null);
  const [autoAudio, setAutoAudio] = useState(() => localStorage.getItem('autoAudio') === 'true');
  const [isSyncing, setIsSyncing] = useState(false);

  const [deviceId] = useState(() => {
    let id = localStorage.getItem('lexDeviceId');
    if (!id) {
      id = crypto.randomUUID();
      localStorage.setItem('lexDeviceId', id);
    }
    return id;
  });

  const [profile, setProfile] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('lexProfile');
    return saved ? JSON.parse(saved) : {
      username: 'Scholar',
      xp: 0,
      rank: RANKS[0].title,
      searchCount: 0,
      arenaWins: 0,
      accuracy: 100,
      streak: 0
    };
  });

  const syncProfile = useCallback(async (newProfile: UserProfile) => {
    setIsSyncing(true);
    try {
      await upsertProfile(deviceId, newProfile);
    } catch (err) {
      console.error("Profile Sync failed:", err);
    } finally {
      setIsSyncing(false);
    }
  }, [deviceId]);

  useEffect(() => {
    const hydrate = async () => {
      // 1. Initial Local Load
      const savedHistory = localStorage.getItem('lexHistory');
      if (savedHistory) setHistory(JSON.parse(savedHistory));

      let currentProfile = { ...profile };

      // 2. Telegram Identity Detection
      const tgUser = isTelegramEnvironment() ? getTelegramUser() : null;
      if (tgUser) {
        initTelegramTheme();
        currentProfile = {
          ...currentProfile,
          username: tgUser.username || `${tgUser.first_name}${tgUser.last_name ? ' ' + tgUser.last_name : ''}`,
          firstName: tgUser.first_name,
          lastName: tgUser.last_name,
          telegramId: tgUser.id,
          languageCode: tgUser.language_code,
        };
      }

      // 3. Cross-Device Cloud Sync (Prioritize Telegram ID)
      try {
        let cloudProfile: UserProfile | null = null;

        if (currentProfile.telegramId) {
          // Check if this Telegram user exists in our DB (on any device)
          cloudProfile = await fetchProfileByTelegramId(currentProfile.telegramId);
        } else {
          // Fallback to local device ID
          cloudProfile = await fetchProfile(deviceId);
        }

        if (cloudProfile) {
          // Merge logic: Take highest XP and latest stats
          currentProfile = {
            ...cloudProfile,
            ...currentProfile, // Telegram info overrides cloud metadata names
            xp: Math.max(cloudProfile.xp, currentProfile.xp),
            searchCount: Math.max(cloudProfile.searchCount, currentProfile.searchCount),
          };
        }
      } catch (err) {
        console.warn("Cloud synchronization point failed.");
      }

      setProfile(currentProfile);
      syncProfile(currentProfile);

      // 4. Historical Archive Sync
      if (currentProfile.telegramId) {
        setIsSyncing(true);
        try {
          const cloudHistory = await fetchUserHistory(currentProfile.telegramId);
          if (cloudHistory && cloudHistory.length > 0) {
            setHistory(prev => {
              const combined = [...cloudHistory, ...prev];
              const uniqueMap = new Map();
              combined.forEach(item => {
                const key = `${item.term}-${item.sourceLang}-${item.targetLang}`;
                if (!uniqueMap.has(key)) uniqueMap.set(key, item);
              });
              return Array.from(uniqueMap.values()).slice(0, 50);
            });
          }
        } catch (err) {
          console.error("Archive merge failed:", err);
        } finally {
          setIsSyncing(false);
        }
      }
    };
    hydrate();
  }, [deviceId]);

  useEffect(() => {
    localStorage.setItem('lexHistory', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    localStorage.setItem('lexProfile', JSON.stringify(profile));
  }, [profile]);

  useEffect(() => {
    localStorage.setItem('autoAudio', String(autoAudio));
  }, [autoAudio]);

  const addEntry = async (entry: LexicalEntry) => {
    setHistory(prev => {
      const filtered = prev.filter(p => p.term.toLowerCase() !== entry.term.toLowerCase());
      return [entry, ...filtered].slice(0, 50);
    });

    const newXp = profile.xp + 2;
    const newRank = RANKS.reduce((prev, curr) => newXp >= curr.minXp ? curr : prev, RANKS[0]);
    const newProfile = { 
      ...profile, 
      xp: newXp, 
      rank: newRank.title,
      searchCount: profile.searchCount + 1 
    };

    setProfile(newProfile);
    syncProfile(newProfile);

    if (profile.telegramId) {
      try {
        await saveUserHistoryEntry(profile.telegramId, entry);
      } catch (err) {
        console.warn("Cloud save deferred.");
      }
    }
  };

  const handleArenaResult = (correctCount: number, totalQuestions: number) => {
    const earnedXp = correctCount * 5;
    const sessionAccuracy = totalQuestions > 0 ? (correctCount / totalQuestions) * 100 : 0;

    const newXp = profile.xp + earnedXp;
    const newRank = RANKS.reduce((prev, curr) => newXp >= curr.minXp ? curr : prev, RANKS[0]);
    const newAccuracy = profile.accuracy === 100 ? sessionAccuracy : (profile.accuracy + sessionAccuracy) / 2;

    const newProfile = { 
      ...profile, 
      xp: newXp, 
      rank: newRank.title,
      arenaWins: profile.arenaWins + 1,
      accuracy: Math.round(newAccuracy),
      streak: correctCount === totalQuestions ? profile.streak + 1 : 0
    };

    setProfile(newProfile);
    syncProfile(newProfile);
  };

  const handleHistoryItemClick = (entry: LexicalEntry) => {
    setActiveEntry(entry);
    setMode(AppMode.DICTIONARY);
  };

  const navigateToDictionary = () => {
    setActiveEntry(null);
    setMode(AppMode.DICTIONARY);
  };

  return (
    <div className="min-h-screen bg-[#fcfcfb] flex flex-col selection:bg-[#7c1a1a]/10 selection:text-[#7c1a1a]">
      <header className="px-6 md:px-12 py-8 max-w-[1400px] mx-auto w-full flex flex-col md:flex-row items-center justify-between gap-6 md:gap-8">
        <div className="flex items-center gap-4 md:gap-6">
          <span 
            onClick={navigateToDictionary}
            className="text-3xl md:text-4xl serif font-black tracking-tighter cursor-pointer text-[#7c1a1a] hover:scale-105 transition-transform"
          >
            LEX.
          </span>
          <div className="h-6 md:h-8 w-[1px] bg-stone-200"></div>
          <div className="flex flex-col">
            <span className="text-[8px] md:text-[10px] uppercase tracking-[0.4em] md:tracking-[0.5em] text-stone-900 font-black leading-none mb-1">
              Polyglot Insight Engine
            </span>
            <span className="text-[7px] md:text-[8px] uppercase tracking-[0.2em] text-stone-300 font-bold">
              Archival Philology
            </span>
          </div>
        </div>

        <nav className="flex items-center gap-6 md:gap-10 text-[8px] md:text-[10px] uppercase tracking-[0.2em] md:tracking-[0.3em] font-black text-stone-400">
          <button 
            onClick={navigateToDictionary} 
            className={`hover:text-[#7c1a1a] transition-all border-b-2 py-1 ${mode === AppMode.DICTIONARY ? 'border-[#7c1a1a] text-stone-900' : 'border-transparent'}`}
          >
            Encyclopedia
          </button>
          <button 
            onClick={() => setMode(AppMode.ARENA)} 
            className={`hover:text-[#7c1a1a] transition-all border-b-2 py-1 ${mode === AppMode.ARENA ? 'border-[#7c1a1a] text-stone-900' : 'border-transparent'}`}
          >
            Arena
          </button>
          <button 
            onClick={() => setMode(AppMode.ARCHIVE)} 
            className={`hover:text-[#7c1a1a] transition-all border-b-2 py-1 ${mode === AppMode.ARCHIVE ? 'border-[#7c1a1a] text-stone-900' : 'border-transparent'}`}
          >
            Chronicles
          </button>
        </nav>
      </header>

      <main className="flex-1">
        <div className="max-w-[1400px] mx-auto px-6 md:px-12 pb-20">
          {mode === AppMode.DICTIONARY && (
            <Dictionary 
              onEntrySaved={addEntry} 
              autoAudio={autoAudio} 
              setAutoAudio={setAutoAudio}
              profile={profile}
              history={history}
              onStartArena={() => setMode(AppMode.ARENA)}
              selectedEntry={activeEntry}
              onEntryClick={handleHistoryItemClick}
            />
          )}

          {mode === AppMode.ARENA && (
            <Arena history={history} onResult={handleArenaResult} />
          )}

          {mode === AppMode.ARCHIVE && (
            <Archive history={history} onEntryClick={handleHistoryItemClick} />
          )}
        </div>
      </main>

      <footer className="py-8 border-t border-stone-100 bg-white/50">
        <div className="max-w-[1400px] mx-auto px-6 md:px-12 flex flex-col md:flex-row justify-between items-center gap-4 text-[9px] md:text-[10px] uppercase tracking-[0.3em] text-stone-400 font-black">
          <div className="flex items-center gap-3 md:gap-4">
             <span>&copy; 2025 LEXICON PHILOLOGY</span>
             <span className="text-stone-200 hidden md:block">/</span>
             <span className={`flex items-center gap-1 transition-colors ${isSyncing ? 'text-[#7c1a1a] animate-pulse' : 'text-stone-400'}`}>
               {isSyncing ? 'Syncing Chronicles...' : 'Archival Integrity Verified'}
             </span>
          </div>
          <div className="flex items-center gap-4 md:gap-8 overflow-x-auto w-full md:w-auto justify-center md:justify-end">
            <span className="flex items-center gap-2 whitespace-nowrap">
              <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
              {profile.rank}
            </span>
            <span className="text-stone-900 whitespace-nowrap">LVL {Math.floor(profile.xp / 1000) + 1}</span>
            <span className="text-stone-300 whitespace-nowrap">{profile.accuracy}% ACCURACY</span>
          </div>
        </div>
      </footer>
    </div>
  );
};

