export default Dictionary;

/**
 * Telegram Mini App (TMA) Integration Service
 * Handles user data extraction and WebApp environment setup.
 */

export interface TelegramUser {
  id: number;
  first_name: string;
  last_name?: string;
  username?: string;
  language_code?: string;
  is_premium?: boolean;
  phone_number?: string;
}

export const getTelegramWebApp = () => {
  return (window as any).Telegram?.WebApp;
};

export const isTelegramEnvironment = () => {
  const tg = getTelegramWebApp();
  return !!(tg && tg.initData);
};

export const getTelegramUser = (): TelegramUser | null => {
  const tg = getTelegramWebApp();
  if (!tg) return null;

  // initDataUnsafe is populated when running inside Telegram
  return tg.initDataUnsafe?.user || null;
};

export const initTelegramTheme = () => {
  const tg = getTelegramWebApp();
  if (!tg) return;

  tg.ready();
  tg.expand();

  // Set the header color to match our Lexicon aesthetic
  tg.setHeaderColor('#fcfcfb');
  tg.setBackgroundColor('#fcfcfb');
};

export const triggerHaptic = (style: 'light' | 'medium' | 'heavy' | 'success' | 'warning' | 'error' = 'light') => {
  const tg = getTelegramWebApp();
  if (!tg?.HapticFeedback) return;

  if (['success', 'warning', 'error'].includes(style)) {
    tg.HapticFeedback.notificationOccurred(style);
  } else {
    tg.HapticFeedback.impactOccurred(style);
  }
};

export const openSupportLink = () => {
  const tg = getTelegramWebApp();
  const supportUrl = 'https://t.me/lex_uz_support';
  triggerHaptic('light');
  if (tg) {
    tg.openTelegramLink(supportUrl);
  } else {
    window.open(supportUrl, '_blank');
  }
};

export const showSupportPopup = () => {
  const tg = getTelegramWebApp();
  if (!tg) return;

  // Only show if not seen in current session
  if (sessionStorage.getItem('support_notified')) return;

  tg.showPopup({
    title: 'Welcome to Lexicon',
    message: 'For suggestions, complaints, or inquiries, please contact our support desk.',
    buttons: [
      { id: 'support', type: 'default', text: 'Contact Support' },
      { id: 'ok', type: 'cancel', text: 'Dismiss' }
    ]
  }, (id: string) => {
    if (id === 'support') {
      openSupportLink();
    }
    sessionStorage.setItem('support_notified', 'true');
  });
};

import React, { useState, useEffect, useCallback } from 'react';
import { AppMode, LexicalEntry, UserProfile } from './types';
import Dictionary from './components/Dictionary';
import Arena from './components/Arena';
import Archive from './components/Archive';
import { RANKS } from './constants';
import { 
  fetchProfile, 
  upsertProfile, 
  fetchUserHistory, 
  saveUserHistoryEntry 
} from './services/supabase';
import { 
  getTelegramUser, 
  initTelegramTheme, 
  isTelegramEnvironment, 
  showSupportPopup,
  openSupportLink
} from './services/telegram';

const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>(AppMode.DICTIONARY);
  const [history, setHistory] = useState<LexicalEntry[]>([]);
  const [activeEntry, setActiveEntry] = useState<LexicalEntry | null>(null);
  const [autoAudio, setAutoAudio] = useState(() => localStorage.getItem('autoAudio') === 'true');
  const [isSyncing, setIsSyncing] = useState(false);

  const [profile, setProfile] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('lexProfile');
    return saved ? JSON.parse(saved) : {
      username: 'Scholar',
      xp: 0,
      rank: RANKS[0].title,
      searchCount: 0,
      arenaWins: 0,
      accuracy: 100,
      streak: 0
    };
  });

  const syncProfile = useCallback(async (newProfile: UserProfile) => {
    if (!newProfile.telegramId) return;
    setIsSyncing(true);
    try {
      await upsertProfile(newProfile);
    } catch (err) {
      console.error("Profile Sync failed:", err);
    } finally {
      setIsSyncing(false);
    }
  }, []);

  useEffect(() => {
    const hydrate = async () => {
      // 1. Initial Local Load (Fast Path)
      const savedHistory = localStorage.getItem('lexHistory');
      if (savedHistory) setHistory(JSON.parse(savedHistory));

      let currentProfile = { ...profile };

      // 2. Telegram Identity Detection
      const tgUser = isTelegramEnvironment() ? getTelegramUser() : null;
      if (tgUser) {
        initTelegramTheme();

        // Show support invitation on entry
        showSupportPopup();

        const fullName = [tgUser.first_name, tgUser.last_name].filter(Boolean).join(' ');
        currentProfile = {
          ...currentProfile,
          username: tgUser.username || fullName || 'Scholar',
          firstName: tgUser.first_name,
          lastName: tgUser.last_name,
          telegramId: tgUser.id,
          phoneNumber: tgUser.phone_number,
          languageCode: tgUser.language_code,
        };
      }

      // 3. Cross-Device Cloud Sync via Telegram ID
      if (currentProfile.telegramId) {
        setIsSyncing(true);
        try {
          const cloudProfile = await fetchProfile(currentProfile.telegramId);
          if (cloudProfile) {
            currentProfile = {
              ...cloudProfile,
              ...currentProfile,
              xp: Math.max(cloudProfile.xp, currentProfile.xp),
              searchCount: Math.max(cloudProfile.searchCount, currentProfile.searchCount),
            };
          }

          const cloudHistory = await fetchUserHistory(currentProfile.telegramId);
          if (cloudHistory && cloudHistory.length > 0) {
            setHistory(prev => {
              const combined = [...cloudHistory, ...prev];
              const uniqueMap = new Map();
              combined.forEach(item => {
                const key = `${item.term}-${item.sourceLang}-${item.targetLang}`;
                if (!uniqueMap.has(key)) uniqueMap.set(key, item);
              });
              return Array.from(uniqueMap.values()).slice(0, 50);
            });
          }
        } catch (err) {
          console.warn("Cloud synchronization failed.");
        } finally {
          setIsSyncing(false);
        }
      }

      setProfile(currentProfile);
      if (currentProfile.telegramId) {
        syncProfile(currentProfile);
      }
    };
    hydrate();
  }, []);

  useEffect(() => {
    localStorage.setItem('lexHistory', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    localStorage.setItem('lexProfile', JSON.stringify(profile));
  }, [profile]);

  useEffect(() => {
    localStorage.setItem('autoAudio', String(autoAudio));
  }, [autoAudio]);

  const addEntry = async (entry: LexicalEntry) => {
    setHistory(prev => {
      const filtered = prev.filter(p => p.term.toLowerCase() !== entry.term.toLowerCase());
      return [entry, ...filtered].slice(0, 50);
    });

    const newXp = profile.xp + 2;
    const newRank = RANKS.reduce((prev, curr) => newXp >= curr.minXp ? curr : prev, RANKS[0]);
    const newProfile = { 
      ...profile, 
      xp: newXp, 
      rank: newRank.title,
      searchCount: profile.searchCount + 1 
    };

    setProfile(newProfile);

    if (newProfile.telegramId) {
      syncProfile(newProfile);
      try {
        await saveUserHistoryEntry(newProfile.telegramId, entry);
      } catch (err) {
        console.warn("Could not save entry to cloud.");
      }
    }
  };

  const handleArenaResult = (correctCount: number, totalQuestions: number) => {
    const earnedXp = correctCount * 5;
    const sessionAccuracy = totalQuestions > 0 ? (correctCount / totalQuestions) * 100 : 0;

    const newXp = profile.xp + earnedXp;
    const newRank = RANKS.reduce((prev, curr) => newXp >= curr.minXp ? curr : prev, RANKS[0]);
    const newAccuracy = profile.accuracy === 100 ? sessionAccuracy : (profile.accuracy + sessionAccuracy) / 2;

    const newProfile = { 
      ...profile, 
      xp: newXp, 
      rank: newRank.title,
      arenaWins: profile.arenaWins + 1,
      accuracy: Math.round(newAccuracy),
      streak: correctCount === totalQuestions ? profile.streak + 1 : 0
    };

    setProfile(newProfile);
    if (newProfile.telegramId) {
      syncProfile(newProfile);
    }
  };

  const handleHistoryItemClick = (entry: LexicalEntry) => {
    setActiveEntry(entry);
    setMode(AppMode.DICTIONARY);
  };

  const navigateToDictionary = () => {
    setActiveEntry(null);
    setMode(AppMode.DICTIONARY);
  };

  const handleSupportClick = (e: React.MouseEvent) => {
    e.preventDefault();
    openSupportLink();
  };

  return (
    <div className="min-h-screen bg-[#fcfcfb] flex flex-col selection:bg-[#7c1a1a]/10 selection:text-[#7c1a1a]">
      <header className="px-6 md:px-12 py-8 max-w-[1400px] mx-auto w-full flex flex-col md:flex-row items-center justify-between gap-6 md:gap-8">
        <div className="flex items-center gap-4 md:gap-6">
          <span 
            onClick={navigateToDictionary}
            className="text-3xl md:text-4xl serif font-black tracking-tighter cursor-pointer text-[#7c1a1a] hover:scale-105 transition-transform"
          >
            LEX.
          </span>
          <div className="h-6 md:h-8 w-[1px] bg-stone-200"></div>
          <div className="flex flex-col">
            <span className="text-[8px] md:text-[10px] uppercase tracking-[0.4em] md:tracking-[0.5em] text-stone-900 font-black leading-none mb-1">
              Polyglot Insight Engine
            </span>
            <span className="text-[7px] md:text-[8px] uppercase tracking-[0.2em] text-stone-300 font-bold">
              Archival Philology
            </span>
          </div>
        </div>

        <nav className="flex items-center gap-6 md:gap-10 text-[8px] md:text-[10px] uppercase tracking-[0.2em] md:tracking-[0.3em] font-black text-stone-400">
          <button 
            onClick={navigateToDictionary} 
            className={`hover:text-[#7c1a1a] transition-all border-b-2 py-1 ${mode === AppMode.DICTIONARY ? 'border-[#7c1a1a] text-stone-900' : 'border-transparent'}`}
          >
            Encyclopedia
          </button>
          <button 
            onClick={() => setMode(AppMode.ARENA)} 
            className={`hover:text-[#7c1a1a] transition-all border-b-2 py-1 ${mode === AppMode.ARENA ? 'border-[#7c1a1a] text-stone-900' : 'border-transparent'}`}
          >
            Arena
          </button>
          <button 
            onClick={() => setMode(AppMode.ARCHIVE)} 
            className={`hover:text-[#7c1a1a] transition-all border-b-2 py-1 ${mode === AppMode.ARCHIVE ? 'border-[#7c1a1a] text-stone-900' : 'border-transparent'}`}
          >
            Chronicles
          </button>
          <button 
            onClick={handleSupportClick}
            className="hover:text-[#7c1a1a] transition-all border-b-2 py-1 border-transparent flex items-center gap-1"
          >
            Support
            <svg xmlns="http://www.w3.org/2000/svg" width="8" height="8" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M18 13v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h6"/><polyline points="15 3 21 3 21 9"/><line x1="10" y1="14" x2="21" y2="3"/></svg>
          </button>
        </nav>
      </header>

      <main className="flex-1">
        <div className="max-w-[1400px] mx-auto px-6 md:px-12 pb-20">
          {mode === AppMode.DICTIONARY && (
            <Dictionary 
              onEntrySaved={addEntry} 
              autoAudio={autoAudio} 
              setAutoAudio={setAutoAudio}
              profile={profile}
              history={history}
              onStartArena={() => setMode(AppMode.ARENA)}
              selectedEntry={activeEntry}
              onEntryClick={handleHistoryItemClick}
            />
          )}

          {mode === AppMode.ARENA && (
            <Arena history={history} onResult={handleArenaResult} />
          )}

          {mode === AppMode.ARCHIVE && (
            <Archive history={history} onEntryClick={handleHistoryItemClick} />
          )}
        </div>
      </main>

      <footer className="py-8 border-t border-stone-100 bg-white/50">
        <div className="max-w-[1400px] mx-auto px-6 md:px-12 flex flex-col md:flex-row justify-between items-center gap-4 text-[9px] md:text-[10px] uppercase tracking-[0.3em] text-stone-400 font-black">
          <div className="flex flex-col md:flex-row items-center gap-3 md:gap-6">
             <div className="flex items-center gap-3 md:gap-4">
               <span>&copy; 2025 LEXICON PHILOLOGY</span>
               <span className="text-stone-200 hidden md:block">/</span>
               <span className={`flex items-center gap-1 transition-colors ${isSyncing ? 'text-[#7c1a1a] animate-pulse' : 'text-stone-400'}`}>
                 {isSyncing ? 'Syncing Chronicles...' : profile.telegramId ? 'Cloud Archives Active' : 'Offline Mode (Local Only)'}
               </span>
             </div>
             <div className="flex items-center gap-4">
               <button onClick={handleSupportClick} className="hover:text-[#7c1a1a] underline decoration-stone-200 underline-offset-4">Suggestions & Complaints</button>
             </div>
          </div>
          <div className="flex items-center gap-4 md:gap-8 overflow-x-auto w-full md:w-auto justify-center md:justify-end">
            <span className="flex items-center gap-2 whitespace-nowrap">
              <span className={`w-2 h-2 rounded-full ${profile.telegramId ? 'bg-green-500 animate-pulse' : 'bg-stone-300'}`}></span>
              {profile.rank}
            </span>
            <span className="text-stone-900 whitespace-nowrap">LVL {Math.floor(profile.xp / 1000) + 1}</span>
            <span className="text-stone-300 whitespace-nowrap">{profile.accuracy}% ACCURACY</span>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Language, LexicalEntry, UserProfile } from '../types';
import { translateWord } from '../services/gemini';
import { speak, resumeAudioContext } from '../services/tts';
import { SEED_ARCHIVE } from '../constants';
import { fetchGlobalEntry, saveGlobalEntry, fetchSuggestions } from '../services/supabase';
import { openSupportLink } from '../services/telegram';
import ResultCard from './ResultCard';
import HistoryGrid from './HistoryGrid';

interface Props {
  onEntrySaved: (entry: LexicalEntry) => void;
  autoAudio: boolean;
  setAutoAudio: (val: boolean) => void;
  profile: UserProfile;
  history: LexicalEntry[];
  onStartArena: () => void;
  selectedEntry?: LexicalEntry | null;
  onEntryClick: (entry: LexicalEntry) => void;
}

interface SuggestionItem {
  term: string;
  source: 'local' | 'global' | 'seed';
}

const LANGUAGES: Record<Language, string> = {
  German: 'GER',
  Uzbek: 'UZB',
  English: 'ENG',
  Russian: 'RUS'
};

const normalize = (text: string, lang: Language): string => {
  let res = text.trim().toLowerCase();
  if (lang === 'German') {
    res = res.replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue').replace(/ß/g, 'ss');
  } else if (lang === 'Russian') {
    res = res.replace(/ё/g, 'е');
  } else if (lang === 'Uzbek') {
    res = res.replace(/[‘’`]/g, "'");
  }
  return res;
};

const Dictionary: React.FC<Props> = ({ 
  onEntrySaved, 
  autoAudio, 
  setAutoAudio, 
  profile, 
  history, 
  onStartArena, 
  selectedEntry,
  onEntryClick
}) => {
  const [query, setQuery] = useState('');
  const [sourceLang, setSourceLang] = useState<Language>('German');
  const [targetLang, setTargetLang] = useState<Language>('Uzbek');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<LexicalEntry | null>(null);
  const [suggestions, setSuggestions] = useState<SuggestionItem[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [selectedIndex, setSelectedIndex] = useState(-1);

  const suggestionRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const handleInteractionWarmup = () => {
    resumeAudioContext();
  };

  useEffect(() => {
    if (selectedEntry) {
      setQuery(selectedEntry.term);
      setResult(selectedEntry);
      setSourceLang(selectedEntry.sourceLang);
      setTargetLang(selectedEntry.targetLang);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [selectedEntry]);

  useEffect(() => {
    const delayDebounce = setTimeout(async () => {
      const trimmedQuery = query.trim().toLowerCase();
      if (trimmedQuery.length >= 2) {
        const localMatches = history
          .filter(e => e.sourceLang === sourceLang && e.term.toLowerCase().includes(trimmedQuery))
          .map(e => ({ term: e.term, source: 'local' as const }));

        const seedMatches = Object.values(SEED_ARCHIVE)
          .filter(e => e?.term && e.term.toLowerCase().includes(trimmedQuery))
          .map(e => ({ term: e!.term!, source: 'seed' as const }));

        let globalMatches: SuggestionItem[] = [];
        try {
          const globalTerms = await fetchSuggestions(query, sourceLang);
          globalMatches = globalTerms.map(term => ({ term, source: 'global' as const }));
        } catch (e) {
          console.warn("Global suggestions fetch failed");
        }

        const combined = [...localMatches, ...seedMatches, ...globalMatches];
        const unique = combined.filter((v, i, a) => 
          a.findIndex(t => t.term.toLowerCase() === v.term.toLowerCase()) === i
        ).slice(0, 8);

        setSuggestions(unique);
        setShowSuggestions(unique.length > 0);
        setSelectedIndex(-1);
      } else {
        setSuggestions([]);
        setShowSuggestions(false);
      }
    }, 250);
    return () => clearTimeout(delayDebounce);
  }, [query, sourceLang, history]);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (suggestionRef.current && !suggestionRef.current.contains(e.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSourceLangChange = (lang: Language) => {
    handleInteractionWarmup();
    if (lang === targetLang) setTargetLang(sourceLang);
    setSourceLang(lang);
  };

  const handleTargetLangChange = (lang: Language) => {
    handleInteractionWarmup();
    if (lang === sourceLang) setSourceLang(targetLang);
    setTargetLang(lang);
  };

  const localCache = useMemo(() => {
    const cache = new Map<string, LexicalEntry>();
    Object.entries(SEED_ARCHIVE).forEach(([key, entry]) => {
      const parts = key.split('-');
      const sL = parts[1] as Language;
      const tL = parts[2] as Language;
      if (entry.term) {
        const norm = normalize(entry.term, sL);
        cache.set(`${norm}-${sL}-${tL}`, { ...entry, id: `seed-${key}`, normalizedTerm: norm, sourceLang: sL, targetLang: tL } as any);
      }
    });
    history.forEach(entry => {
      const norm = normalize(entry.term, entry.sourceLang);
      cache.set(`${norm}-${entry.sourceLang}-${entry.targetLang}`, entry);
    });
    return cache;
  }, [history]);

  const handleSearch = async (overrideQuery?: string) => {
    await resumeAudioContext(); 
    const cleanQuery = (overrideQuery || query).trim();
    if (!cleanQuery) return;

    setShowSuggestions(false);
    if (autoAudio) speak(cleanQuery, sourceLang);

    const normQuery = normalize(cleanQuery, sourceLang);
    const cacheKey = `${normQuery}-${sourceLang}-${targetLang}`;

    const localHit = localCache.get(cacheKey);
    if (localHit) {
      setResult(localHit);
      setQuery(localHit.term);
      return;
    }

    setLoading(true);
    setResult(null);

    try {
      const globalHit = await fetchGlobalEntry(normQuery, sourceLang, targetLang);
      if (globalHit) {
        setResult(globalHit);
        setQuery(globalHit.term);
        onEntrySaved(globalHit);
        setLoading(false);
        return;
      }

      const finalEntry = await translateWord(cleanQuery, sourceLang, targetLang);
      finalEntry.normalizedTerm = normQuery;

      setResult(finalEntry);
      setQuery(finalEntry.term);
      onEntrySaved(finalEntry);
      saveGlobalEntry(finalEntry);
    } catch (err) {
      console.error("Philologist Engine Error:", err);
    } finally {
      setLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (!showSuggestions) return;

    if (e.key === 'ArrowDown') {
      e.preventDefault();
      setSelectedIndex(prev => (prev + 1) % suggestions.length);
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      setSelectedIndex(prev => (prev - 1 + suggestions.length) % suggestions.length);
    } else if (e.key === 'Enter' && selectedIndex >= 0) {
      e.preventDefault();
      const selected = suggestions[selectedIndex];
      setQuery(selected.term);
      handleSearch(selected.term);
    } else if (e.key === 'Escape') {
      setShowSuggestions(false);
    }
  };

  const swapLanguages = () => {
    handleInteractionWarmup();
    const prevSource = sourceLang;
    setSourceLang(targetLang);
    setTargetLang(prevSource);
  };

  const handleSupportClick = (e: React.MouseEvent) => {
    e.preventDefault();
    openSupportLink();
  };

  return (
    <div className="space-y-6 md:space-y-12 max-w-7xl mx-auto">
      {/* Header Info */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6 pt-4">
        <div className="flex items-center gap-6">
          <div className="space-y-1 border-l-[2px] border-[#7c1a1a] pl-4 block">
            <span className="text-[9px] uppercase tracking-[0.4em] text-stone-400 font-black">Philological Mastery</span>
            <div className="flex items-baseline gap-2">
              <span className="text-xl md:text-2xl font-black serif text-stone-900 leading-none">{profile.xp}</span>
              <span className="text-[8px] uppercase tracking-widest text-stone-300 font-bold">Total XP</span>
            </div>
          </div>
          <button onClick={handleSupportClick} className="flex flex-col items-start group text-left">
            <span className="text-[9px] uppercase tracking-[0.4em] text-stone-300 font-black group-hover:text-[#7c1a1a] transition-colors">Inquiries?</span>
            <span className="text-[10px] serif italic text-stone-400 font-medium group-hover:text-[#7c1a1a] transition-colors">Feedback & Support</span>
          </button>
        </div>

        <div className="flex flex-col lg:flex-row items-center gap-6 lg:gap-12 w-full md:w-auto">
          <div className="flex flex-col sm:flex-row items-center gap-3 bg-stone-50 p-1.5 rounded-sm w-full sm:w-auto border border-stone-100">
             <div className="grid grid-cols-4 bg-white shadow-sm overflow-hidden rounded-sm w-full sm:w-auto">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button key={full} type="button" onClick={() => handleSourceLangChange(full)}
                    className={`px-2 sm:px-4 py-2 text-[8px] sm:text-[9px] font-black tracking-widest border-r border-stone-100 last:border-r-0 transition-all ${sourceLang === full ? 'bg-stone-900 text-white' : 'text-stone-300 hover:text-stone-600'}`}>
                    {short}
                  </button>
                ))}
             </div>
             <button type="button" onClick={swapLanguages} className="text-stone-300 hover:text-[#7c1a1a] transition-all p-1 hover:rotate-180 duration-500 transform sm:rotate-0 rotate-90">
               <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="m17 2 4 4-4 4"/><path d="M3 11v-1a4 4 0 0 1 4-4h14"/><path d="m7 22-4-4 4-4"/><path d="M21 13v1a4 4 0 0 1-4 4H3"/></svg>
             </button>
             <div className="grid grid-cols-4 bg-white shadow-sm overflow-hidden rounded-sm w-full sm:w-auto">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button key={full} type="button" onClick={() => handleTargetLangChange(full)}
                    className={`px-2 sm:px-4 py-2 text-[8px] sm:text-[9px] font-black tracking-widest border-r border-stone-100 last:border-r-0 transition-all ${targetLang === full ? 'bg-[#7c1a1a] text-white' : 'text-stone-300 hover:text-stone-600'}`}>
                    {short}
                  </button>
                ))}
             </div>
          </div>
          <div className="flex items-center gap-3 bg-stone-50/50 px-3 py-1.5 rounded-full border border-stone-100">
            <span className="text-[9px] uppercase tracking-[0.2em] text-stone-400 font-black">AUTO-PRONOUNCE</span>
            <button onClick={() => { handleInteractionWarmup(); setAutoAudio(!autoAudio); }} className={`w-8 h-4 rounded-full relative transition-all duration-300 p-0.5 ${autoAudio ? 'bg-[#7c1a1a]' : 'bg-stone-200'}`}>
              <div className={`w-3 h-3 bg-white rounded-full transition-all shadow-sm ${autoAudio ? 'translate-x-4' : 'translate-x-0'}`} />
            </button>
          </div>
        </div>
      </div>

      <div className="relative w-full" ref={suggestionRef}>
        <form onSubmit={(e) => { e.preventDefault(); handleSearch(); }} className="relative z-20">
          <div className="bg-white border border-stone-200 shadow-sm hover:border-[#7c1a1a]/50 focus-within:border-[#7c1a1a] focus-within:ring-4 focus-within:ring-[#7c1a1a]/5 transition-all group rounded-sm overflow-hidden flex items-stretch min-h-[60px] md:min-h-[100px]">
            <div className="flex-1 flex items-center px-4 md:px-10">
              <input 
                ref={inputRef}
                type="text" 
                value={query} 
                onChange={(e) => setQuery(e.target.value)} 
                onFocus={() => { handleInteractionWarmup(); if (suggestions.length > 0) setShowSuggestions(true); }}
                onKeyDown={handleKeyDown}
                placeholder="Summon an inscription..."
                className="w-full text-xl md:text-5xl serif bg-transparent outline-none text-stone-900 placeholder:text-stone-200 lowercase font-medium tracking-tighter leading-none" 
              />
            </div>
            <button type="submit" disabled={loading} className="bg-stone-50 border-l border-stone-100 px-4 md:px-10 text-stone-300 hover:text-[#7c1a1a] hover:bg-white transition-all transform active:scale-95 flex items-center justify-center">
              {loading ? <div className="w-5 h-5 md:w-10 md:h-10 border-[3px] border-[#7c1a1a] border-t-transparent rounded-full animate-spin" /> : <svg xmlns="http://www.w3.org/2000/svg" className="w-5 h-5 md:w-12 md:h-12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="m12 5 7 7-7 7"/></svg>}
            </button>
          </div>
        </form>

        {showSuggestions && (
          <div className="absolute top-full left-0 right-0 bg-white border border-stone-200 shadow-2xl z-10 animate-in fade-in slide-in-from-top-2 duration-300 rounded-b-sm overflow-hidden max-h-[350px] overflow-y-auto">
             {suggestions.map((s, idx) => (
               <button 
                 key={idx} 
                 onClick={() => { setQuery(s.term); handleSearch(s.term); }}
