      <footer className="py-8 border-t border-stone-100 bg-white/50">
        <div className="max-w-[1400px] mx-auto px-6 md:px-12 flex flex-col md:flex-row justify-between items-center gap-4 text-[9px] md:text-[10px] uppercase tracking-[0.3em] text-stone-400 font-black">
          <div className="flex flex-col md:flex-row items-center gap-3 md:gap-6">
             <div className="flex items-center gap-3 md:gap-4">
               <span>&copy; 2025 LEXICON PHILOLOGY</span>
               <span className="text-stone-200 hidden md:block">/</span>
