  const [cloudActive, setCloudActive] = useState(false);

  const initialHydrationRef = useRef(false);

  const [profile, setProfile] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('lexProfile');
    return saved ? JSON.parse(saved) : {
      username: 'Scholar',
      xp: 0,
      rank: RANKS[0].title,
      searchCount: 0,
      arenaWins: 0,
      accuracy: 100,
      streak: 0
    };
  });

  const syncProfileToCloud = useCallback(async (newProfile: UserProfile) => {
    if (!newProfile.telegramId) return;
    setIsSyncing(true);
    try {
      await upsertProfile(newProfile);
      setCloudActive(true);
    } catch (err) {
      console.error("Cloud Archive Sync Failed:", err);
      setCloudActive(false);
    } finally {
      setIsSyncing(false);
    }
  }, []);

  // Identity and Hydration Logic
  useEffect(() => {
    if (initialHydrationRef.current) return;
    initialHydrationRef.current = true;

    const performHydration = async () => {
      // 1. Local Storage Recovery
      const savedHistory = localStorage.getItem('lexHistory');
      if (savedHistory) setHistory(JSON.parse(savedHistory));

      let currentProfile = { ...profile };

      // 2. Telegram Environment Integration
      const tgUser = isTelegramEnvironment() ? getTelegramUser() : null;
      if (tgUser) {
        initTelegramTheme();

        const fullName = [tgUser.first_name, tgUser.last_name].filter(Boolean).join(' ');
        currentProfile = {
          ...currentProfile,
          username: tgUser.username || fullName || 'Scholar',
          firstName: tgUser.first_name,
          lastName: tgUser.last_name,
          telegramId: tgUser.id,
          phoneNumber: tgUser.phone_number,
          languageCode: tgUser.language_code,
        };
      }

      // 3. Cloud Archive Fetch
      if (currentProfile.telegramId) {
        setIsSyncing(true);
        try {
          const [cloudProf, cloudHist] = await Promise.all([
            fetchProfile(currentProfile.telegramId),
            fetchUserHistory(currentProfile.telegramId)
