const handleSupabaseError = (error: any, tableName: string) => {
  if (error?.code === 'PGRST204' || error?.code === 'PGRST205' || error?.status === 404 || error?.message?.includes('does not exist')) {
    console.warn(`Supabase Alert: Table '${tableName}' not found or unreachable.`);
    return true;
  }
  console.error(`Supabase Error [${tableName}]:`, error);
  return false;
};

export async function fetchSuggestions(query: string, sourceLang: Language): Promise<string[]> {
  if (query.length < 2) return [];
  try {
    const cleanQuery = query.toLowerCase().trim();
    const { data, error } = await supabase
      .from('lex_entries')
      .select('term')
      .eq('source_lang', sourceLang)
      .ilike('normalized_term', `${cleanQuery}%`)
      .limit(10);

    if (error) {
      handleSupabaseError(error, 'lex_entries');
      return [];
    }
    return Array.from(new Set(data?.map(d => d.term).filter(Boolean) || []));
  } catch {
    return [];
  }
}

export async function fetchGlobalEntry(
  normalizedTerm: string,
  sourceLang: Language,
  targetLang: Language
): Promise<LexicalEntry | null> {
  try {
    const { data, error } = await supabase
      .from('lex_entries')
      .select('entry_data')
      .eq('normalized_term', normalizedTerm)
      .eq('source_lang', sourceLang)
      .eq('target_lang', targetLang)
      .maybeSingle();

    if (error) {
      handleSupabaseError(error, 'lex_entries');
      return null;
    }
    return (data?.entry_data as LexicalEntry) || null;
  } catch {
    return null;
  }
}

export async function saveGlobalEntry(entry: LexicalEntry) {
  try {
    await supabase
      .from('lex_entries')
      .upsert({
        term: entry.term,
        normalized_term: entry.normalizedTerm,
        source_lang: entry.sourceLang,
        target_lang: entry.targetLang,
        entry_data: entry
      }, { onConflict: 'normalized_term, source_lang, target_lang' });
  } catch {}
}

export async function fetchProfile(telegramId: number): Promise<UserProfile | null> {
  try {
    const { data, error } = await supabase
      .from('lex_profiles')
      .select('profile_data')
      .eq('telegram_id', telegramId)
      .maybeSingle();

    if (error) {
      handleSupabaseError(error, 'lex_profiles');
      return null;
    }
    return (data?.profile_data as UserProfile) || null;
  } catch (err) {
    console.error("Profile Fetch Failed:", err);
    return null;
  }
}

export async function fetchUserHistory(telegramId: number): Promise<LexicalEntry[]> {
  try {
    const { data, error } = await supabase
      .from('lex_user_history')
      .select('entry_data')
      .eq('telegram_id', telegramId)
      .order('created_at', { ascending: false })
      .limit(50);

    if (error) {
      handleSupabaseError(error, 'lex_user_history');
      return [];
    }
    return data?.map(d => d.entry_data as LexicalEntry) || [];
  } catch {
    return [];
  }
}

export async function saveUserHistoryEntry(telegramId: number, entry: LexicalEntry) {
  try {
    const { error } = await supabase
      .from('lex_user_history')
      .upsert({
        telegram_id: telegramId,
        entry_id: entry.id,
        entry_data: entry,
        created_at: new Date().toISOString()
      }, { onConflict: 'telegram_id, entry_id' });

    if (error) handleSupabaseError(error, 'lex_user_history');
  } catch (err) {
    console.error("History Sync Failed:", err);
  }
}

export async function upsertProfile(profile: UserProfile) {
  if (!profile.telegramId) return;
  try {
    // Only update progress metrics, keeping identity fields intact
    const { error } = await supabase
      .from('lex_profiles')
      .update({ 
        profile_data: profile,
        updated_at: new Date().toISOString() 
      })
      .eq('telegram_id', profile.telegramId);

    if (error) handleSupabaseError(error, 'lex_profiles');
  } catch (err) {
    console.error("Profile Upsert Failed:", err);
  }
}

/**
 * Telegram Mini App (TMA) Integration Service
 * Strictly restricted to identity lookup per privacy policy.
 */

export interface TelegramIdentity {
  id: number;
}

export const getTelegramWebApp = () => {
  return (window as any).Telegram?.WebApp;
};

export const isTelegramEnvironment = () => {
  const tg = getTelegramWebApp();
  return !!(tg && tg.initData);
};

/**
 * Returns ONLY the telegram_id. 
 * Per policy, personal fields (names, phone) are fetched from the backend.
 */
export const getTelegramUserId = (): number | null => {
  const tg = getTelegramWebApp();
  if (!tg) return null;
  return tg.initDataUnsafe?.user?.id || null;
};

export const initTelegramTheme = () => {
  const tg = getTelegramWebApp();
  if (!tg) return;

  tg.ready();
  tg.expand();

  tg.setHeaderColor('#fcfcfb');
  tg.setBackgroundColor('#fcfcfb');
};

export const triggerHaptic = (style: 'light' | 'medium' | 'heavy' | 'success' | 'warning' | 'error' = 'light') => {
  const tg = getTelegramWebApp();
  if (!tg?.HapticFeedback) return;

  if (['success', 'warning', 'error'].includes(style)) {
    tg.HapticFeedback.notificationOccurred(style);
  } else {
    tg.HapticFeedback.impactOccurred(style);
  }
};

export const openTelegramLink = (url: string) => {
  const tg = getTelegramWebApp();
  if (tg && tg.openTelegramLink) {
    tg.openTelegramLink(url);
  } else {
    window.open(url, '_blank');
  }
};

