async function saveProfile(user: any, phoneNumber?: string) {
  const profileData = {
    telegramId: user.id,
    username: user.username || 'Scholar',
    firstName: user.first_name,
    lastName: user.last_name || '',
    phoneNumber: phoneNumber || null,
    languageCode: user.language_code || 'en',
