bot.command("start", async (ctx) => {
  const userId = ctx.from?.id;
  if (!userId) return;

  const { data: existing } = await supabase
    .from('lex_profiles')
    .select('telegram_id')
    .eq('telegram_id', userId)
    .maybeSingle();

  if (existing) {
    return sendWelcomeMessage(ctx);
  }

  // Verification request with Optional Phone Number
  const kb = new Keyboard()
    .requestContact("📜 Share Phone (Verify)")
    .row()
    .text("🚀 Skip & Start")
    .oneTime()
    .resized();

  await ctx.reply(
    `👋 *Welcome to UzGer Lexicon (LEX.)*\n\nTo archive your progress in the cloud, we need to initialize your scholarly profile. Sharing your contact helps secure your account across devices (optional).`,
    { parse_mode: "Markdown", reply_markup: kb }
  );
});

bot.on("message:contact", async (ctx) => {
  if (ctx.message.contact?.user_id !== ctx.from.id) {
    return ctx.reply("Verification must match your own identity.");
  }
  await saveProfile(ctx.from, ctx.message.contact.phone_number);
  await ctx.reply("✅ Profile verified with contact. Archival cloud active.", { reply_markup: { remove_keyboard: true } });
  await sendWelcomeMessage(ctx);
});

bot.on("message:text", async (ctx) => {
  if (ctx.message.text === "🚀 Skip & Start") {
    const { data: existing } = await supabase.from('lex_profiles').select('id').eq('telegram_id', ctx.from.id).maybeSingle();
    if (!existing) {
      await saveProfile(ctx.from);
    }
    await ctx.reply("✅ Profile initialized. Welcome, Scholar.", { reply_markup: { remove_keyboard: true } });
    await sendWelcomeMessage(ctx);
  }
});

