            onClick={() => { setActiveEntry(null); setMode(AppMode.DICTIONARY); }}
            className="text-3xl md:text-4xl serif font-black tracking-tighter cursor-pointer text-[#7c1a1a] hover:scale-105 transition-transform"
          >
            LEX.
          </span>
          <div className="h-6 md:h-8 w-[1px] bg-stone-200"></div>
          <div className="flex flex-col">
            <span className="text-[8px] md:text-[10px] uppercase tracking-[0.4em] md:tracking-[0.5em] text-stone-900 font-black leading-none mb-1">
              Polyglot Insight Engine
            </span>
            <span className="text-[7px] md:text-[8px] uppercase tracking-[0.2em] text-stone-300 font-bold">
              Archival Philology
            </span>
          </div>
        </div>

        <nav className="flex items-center gap-6 md:gap-10 text-[8px] md:text-[10px] uppercase tracking-[0.2em] md:tracking-[0.3em] font-black text-stone-400">
          <button 
            onClick={() => { setActiveEntry(null); setMode(AppMode.DICTIONARY); }} 
            className={`hover:text-[#7c1a1a] transition-all border-b-2 py-1 ${mode === AppMode.DICTIONARY ? 'border-[#7c1a1a] text-stone-900' : 'border-transparent'}`}
          >
            Encyclopedia
          </button>
          <button 
            onClick={() => setMode(AppMode.ARENA)} 
            className={`hover:text-[#7c1a1a] transition-all border-b-2 py-1 ${mode === AppMode.ARENA ? 'border-[#7c1a1a] text-stone-900' : 'border-transparent'}`}
