import { GoogleGenAI, Modality } from "@google/genai";
import { Language } from "../types";
import { VOICE_MAPPING } from "../constants";

const audioBufferCache = new Map<string, AudioBuffer>();
let sharedAudioCtx: AudioContext | null = null;

/**
 * Returns the singleton AudioContext.
 * Fixed sample rate of 24000 is critical for Gemini PCM matching.
 */
export function getAudioContext() {
  if (!sharedAudioCtx) {
    sharedAudioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
  }
  return sharedAudioCtx;
}

/**
 * Aggressively resumes the AudioContext.
 * Plays a silent "pip" to ensure the hardware pipe stays open on mobile.
 */
export async function resumeAudioContext() {
  const ctx = getAudioContext();
  if (ctx.state === 'running') return;

  try {
    await ctx.resume();

    // Force mobile hardware to wake up if still suspended
    if (ctx.state !== 'running') {
      const oscillator = ctx.createOscillator();
      const gainNode = ctx.createGain();
      gainNode.gain.value = 0.001; // Nearly silent
      oscillator.connect(gainNode);
      gainNode.connect(ctx.destination);
      oscillator.start(0);
      oscillator.stop(0.01);
      await ctx.resume();
    }
  } catch (e) {
    console.warn("Audio Context Warmup Failed:", e);
  }
}

// Manual base64 decoding
function decode(base64: string) {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

// PCM Decoding to AudioBuffer
async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

/**
 * Main TTS logic with pre-warming to handle network latency gaps.
 */
export async function speak(text: string, lang: Language) {
  if (!text) return;

  try {
    const cacheKey = `${text}-${lang}`;
    const audioCtx = getAudioContext();

    // 1. Initial Warmup: Ensures the gesture that triggered 'speak' is captured
    await resumeAudioContext();

    const startSource = (buffer: AudioBuffer) => {
      // 2. Final Sanity Check: Resume again right before playing in case of network delay
      if (audioCtx.state !== 'running') {
        audioCtx.resume().then(() => {
          const source = audioCtx.createBufferSource();
          source.buffer = buffer;
          source.connect(audioCtx.destination);
          source.start(0);
        });
      } else {
        const source = audioCtx.createBufferSource();
        source.buffer = buffer;
        source.connect(audioCtx.destination);
        source.start(0);
      }
    };

    if (audioBufferCache.has(cacheKey)) {
      startSource(audioBufferCache.get(cacheKey)!);
      return;
    }

    const voiceName = VOICE_MAPPING[lang] || 'Puck';
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Fetch generation
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Read this clearly: ${text}` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) return;

    const audioBuffer = await decodeAudioData(
      decode(base64Audio),
      audioCtx,
      24000,
      1
    );

    audioBufferCache.set(cacheKey, audioBuffer);
    startSource(audioBuffer);
  } catch (error) {
    console.error("Philologist Voice Engine Failure:", error);
  }
}

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Language, LexicalEntry, UserProfile } from '../types';
import { translateWord } from '../services/gemini';
import { speak, resumeAudioContext } from '../services/tts';
import { SEED_ARCHIVE } from '../constants';
import { fetchGlobalEntry, saveGlobalEntry, fetchSuggestions } from '../services/supabase';
import ResultCard from './ResultCard';
import HistoryGrid from './HistoryGrid';

interface Props {
  onEntrySaved: (entry: LexicalEntry) => void;
  autoAudio: boolean;
  setAutoAudio: (val: boolean) => void;
  profile: UserProfile;
  history: LexicalEntry[];
  onStartArena: () => void;
  selectedEntry?: LexicalEntry | null;
  onEntryClick: (entry: LexicalEntry) => void;
}

interface SuggestionItem {
  term: string;
  source: 'local' | 'global' | 'seed';
}

const LANGUAGES: Record<Language, string> = {
  German: 'GER',
  Uzbek: 'UZB',
  English: 'ENG',
  Russian: 'RUS'
};

const normalize = (text: string, lang: Language): string => {
  let res = text.trim().toLowerCase();
  if (lang === 'German') {
    res = res.replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue').replace(/ß/g, 'ss');
  } else if (lang === 'Russian') {
    res = res.replace(/ё/g, 'е');
  } else if (lang === 'Uzbek') {
    res = res.replace(/[‘’`]/g, "'");
  }
  return res;
};

const Dictionary: React.FC<Props> = ({ 
  onEntrySaved, 
  autoAudio, 
  setAutoAudio, 
  profile, 
  history, 
  onStartArena, 
  selectedEntry,
  onEntryClick
}) => {
  const [query, setQuery] = useState('');
  const [sourceLang, setSourceLang] = useState<Language>('German');
  const [targetLang, setTargetLang] = useState<Language>('Uzbek');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<LexicalEntry | null>(null);
  const [suggestions, setSuggestions] = useState<SuggestionItem[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [selectedIndex, setSelectedIndex] = useState(-1);

  const suggestionRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (selectedEntry) {
      setQuery(selectedEntry.term);
      setResult(selectedEntry);
      setSourceLang(selectedEntry.sourceLang);
      setTargetLang(selectedEntry.targetLang);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [selectedEntry]);

  useEffect(() => {
    const delayDebounce = setTimeout(async () => {
      const trimmedQuery = query.trim().toLowerCase();
      if (trimmedQuery.length >= 2) {
        const localMatches = history
          .filter(e => e.sourceLang === sourceLang && e.term.toLowerCase().includes(trimmedQuery))
          .map(e => ({ term: e.term, source: 'local' as const }));

        const seedMatches = Object.values(SEED_ARCHIVE)
          .filter(e => e?.term && e.term.toLowerCase().includes(trimmedQuery))
          .map(e => ({ term: e!.term!, source: 'seed' as const }));

        let globalMatches: SuggestionItem[] = [];
        try {
          const globalTerms = await fetchSuggestions(query, sourceLang);
          globalMatches = globalTerms.map(term => ({ term, source: 'global' as const }));
        } catch (e) {
          console.warn("Global suggestions fetch failed");
        }

        const combined = [...localMatches, ...seedMatches, ...globalMatches];
        const unique = combined.filter((v, i, a) => 
          a.findIndex(t => t.term.toLowerCase() === v.term.toLowerCase()) === i
        ).slice(0, 8);

        setSuggestions(unique);
        setShowSuggestions(unique.length > 0);
        setSelectedIndex(-1);
      } else {
        setSuggestions([]);
        setShowSuggestions(false);
      }
    }, 250);
    return () => clearTimeout(delayDebounce);
  }, [query, sourceLang, history]);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (suggestionRef.current && !suggestionRef.current.contains(e.target as Node)) {
        setShowSuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleSourceLangChange = (lang: Language) => {
    resumeAudioContext();
    if (lang === targetLang) setTargetLang(sourceLang);
    setSourceLang(lang);
  };

  const handleTargetLangChange = (lang: Language) => {
    resumeAudioContext();
    if (lang === sourceLang) setSourceLang(targetLang);
    setTargetLang(lang);
  };

  const localCache = useMemo(() => {
    const cache = new Map<string, LexicalEntry>();
    Object.entries(SEED_ARCHIVE).forEach(([key, entry]) => {
      const parts = key.split('-');
      const sL = parts[1] as Language;
      const tL = parts[2] as Language;
      if (entry.term) {
        const norm = normalize(entry.term, sL);
        cache.set(`${norm}-${sL}-${tL}`, { ...entry, id: `seed-${key}`, normalizedTerm: norm, sourceLang: sL, targetLang: tL } as any);
      }
    });
    history.forEach(entry => {
      const norm = normalize(entry.term, entry.sourceLang);
      cache.set(`${norm}-${entry.sourceLang}-${entry.targetLang}`, entry);
    });
    return cache;
  }, [history]);

  const handleSearch = async (overrideQuery?: string) => {
    // Crucial: Warm up the audio pipe on the user click event
    await resumeAudioContext(); 

    const cleanQuery = (overrideQuery || query).trim();
    if (!cleanQuery) return;

    setShowSuggestions(false);

    // Speak the query word immediately if autoAudio is enabled
    if (autoAudio) speak(cleanQuery, sourceLang);

    const normQuery = normalize(cleanQuery, sourceLang);
    const cacheKey = `${normQuery}-${sourceLang}-${targetLang}`;

    const localHit = localCache.get(cacheKey);
    if (localHit) {
      setResult(localHit);
      setQuery(localHit.term);
      // Auto-pronounce the result if it was a cache hit
      if (autoAudio) {
        setTimeout(() => speak(localHit.mainTranslation, targetLang), 400);
      }
      return;
    }

    setLoading(true);
    setResult(null);

    try {
      const globalHit = await fetchGlobalEntry(normQuery, sourceLang, targetLang);
      if (globalHit) {
        setResult(globalHit);
        setQuery(globalHit.term);
        onEntrySaved(globalHit);
        setLoading(false);
        if (autoAudio) {
          setTimeout(() => speak(globalHit.mainTranslation, targetLang), 400);
        }
        return;
      }

      const finalEntry = await translateWord(cleanQuery, sourceLang, targetLang);
      finalEntry.normalizedTerm = normQuery;

      setResult(finalEntry);
      setQuery(finalEntry.term);
      onEntrySaved(finalEntry);
      saveGlobalEntry(finalEntry);

      // Auto-pronounce the fresh result
      if (autoAudio) {
        setTimeout(() => speak(finalEntry.mainTranslation, targetLang), 400);
      }
    } catch (err) {
      console.error("Philologist Engine Error:", err);
    } finally {
      setLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      resumeAudioContext(); // Warmup on keypress
    }
    if (!showSuggestions) return;

    if (e.key === 'ArrowDown') {
      e.preventDefault();
      setSelectedIndex(prev => (prev + 1) % suggestions.length);
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      setSelectedIndex(prev => (prev - 1 + suggestions.length) % suggestions.length);
    } else if (e.key === 'Enter' && selectedIndex >= 0) {
      e.preventDefault();
      const selected = suggestions[selectedIndex];
      setQuery(selected.term);
      handleSearch(selected.term);
    } else if (e.key === 'Escape') {
      setShowSuggestions(false);
    }
  };

  const swapLanguages = () => {
    resumeAudioContext();
    const prevSource = sourceLang;
    setSourceLang(targetLang);
    setTargetLang(prevSource);
  };

  return (
    <div className="space-y-6 md:space-y-12 max-w-7xl mx-auto">
      {/* Header Info */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6 pt-4">
        <div className="flex items-center gap-6">
          <div className="space-y-1 border-l-[2px] border-[#7c1a1a] pl-4 block">
            <span className="text-[9px] uppercase tracking-[0.4em] text-stone-400 font-black">Philological Mastery</span>
            <div className="flex items-baseline gap-2">
              <span className="text-xl md:text-2xl font-black serif text-stone-900 leading-none">{profile.xp}</span>
              <span className="text-[8px] uppercase tracking-widest text-stone-300 font-bold">Total XP</span>
            </div>
          </div>
        </div>

        <div className="flex flex-col lg:flex-row items-center gap-6 lg:gap-12 w-full md:w-auto">
          <div className="flex flex-col sm:flex-row items-center gap-3 bg-stone-50 p-1.5 rounded-sm w-full sm:w-auto border border-stone-100">
             <div className="grid grid-cols-4 bg-white shadow-sm overflow-hidden rounded-sm w-full sm:w-auto">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button key={full} type="button" onClick={() => handleSourceLangChange(full)}
                    className={`px-2 sm:px-4 py-2 text-[8px] sm:text-[9px] font-black tracking-widest border-r border-stone-100 last:border-r-0 transition-all ${sourceLang === full ? 'bg-stone-900 text-white' : 'text-stone-300 hover:text-stone-600'}`}>
                    {short}
                  </button>
                ))}
             </div>
             <button type="button" onClick={swapLanguages} className="text-stone-300 hover:text-[#7c1a1a] transition-all p-1 hover:rotate-180 duration-500 transform sm:rotate-0 rotate-90">
               <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="m17 2 4 4-4 4"/><path d="M3 11v-1a4 4 0 0 1 4-4h14"/><path d="m7 22-4-4 4-4"/><path d="M21 13v1a4 4 0 0 1-4 4H3"/></svg>
             </button>
             <div className="grid grid-cols-4 bg-white shadow-sm overflow-hidden rounded-sm w-full sm:w-auto">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button key={full} type="button" onClick={() => handleTargetLangChange(full)}
                    className={`px-2 sm:px-4 py-2 text-[8px] sm:text-[9px] font-black tracking-widest border-r border-stone-100 last:border-r-0 transition-all ${targetLang === full ? 'bg-[#7c1a1a] text-white' : 'text-stone-300 hover:text-stone-600'}`}>
                    {short}
                  </button>
                ))}
             </div>
          </div>
          <div className="flex items-center gap-3 bg-stone-50/50 px-3 py-1.5 rounded-full border border-stone-100">
            <span className="text-[9px] uppercase tracking-[0.2em] text-stone-400 font-black">AUTO-PRONOUNCE</span>
            <button onClick={() => { resumeAudioContext(); setAutoAudio(!autoAudio); }} className={`w-8 h-4 rounded-full relative transition-all duration-300 p-0.5 ${autoAudio ? 'bg-[#7c1a1a]' : 'bg-stone-200'}`}>
              <div className={`w-3 h-3 bg-white rounded-full transition-all shadow-sm ${autoAudio ? 'translate-x-4' : 'translate-x-0'}`} />
            </button>
          </div>
        </div>
      </div>

      <div className="relative w-full" ref={suggestionRef}>
        <form onSubmit={(e) => { e.preventDefault(); handleSearch(); }} className="relative z-20">
          <div className="bg-white border border-stone-200 shadow-sm hover:border-[#7c1a1a]/50 focus-within:border-[#7c1a1a] focus-within:ring-4 focus-within:ring-[#7c1a1a]/5 transition-all group rounded-sm overflow-hidden flex items-stretch min-h-[60px] md:min-h-[100px]">
            <div className="flex-1 flex items-center px-4 md:px-10">
              <input 
                ref={inputRef}
                type="text" 
                value={query} 
                onChange={(e) => setQuery(e.target.value)} 
                onFocus={() => { resumeAudioContext(); if (suggestions.length > 0) setShowSuggestions(true); }}
                onKeyDown={handleKeyDown}
                placeholder="Summon an inscription..."
                className="w-full text-xl md:text-5xl serif bg-transparent outline-none text-stone-900 placeholder:text-stone-200 lowercase font-medium tracking-tighter leading-none" 
              />
            </div>
            <button type="submit" disabled={loading} className="bg-stone-50 border-l border-stone-100 px-4 md:px-10 text-stone-300 hover:text-[#7c1a1a] hover:bg-white transition-all transform active:scale-95 flex items-center justify-center">
              {loading ? <div className="w-5 h-5 md:w-10 md:h-10 border-[3px] border-[#7c1a1a] border-t-transparent rounded-full animate-spin" /> : <svg xmlns="http://www.w3.org/2000/svg" className="w-5 h-5 md:w-12 md:h-12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="m12 5 7 7-7 7"/></svg>}
            </button>
          </div>
        </form>

        {showSuggestions && (
          <div className="absolute top-full left-0 right-0 bg-white border border-stone-200 shadow-2xl z-10 animate-in fade-in slide-in-from-top-2 duration-300 rounded-b-sm overflow-hidden max-h-[350px] overflow-y-auto">
             {suggestions.map((s, idx) => (
               <button 
                 key={idx} 
                 onClick={() => { setQuery(s.term); handleSearch(s.term); }}
                 onMouseEnter={() => setSelectedIndex(idx)}
                 className={`w-full text-left px-6 md:px-10 py-3.5 hover:bg-stone-50 border-b border-stone-50 last:border-0 flex items-center justify-between group transition-all ${selectedIndex === idx ? 'bg-stone-50 border-l-[3px] border-l-[#7c1a1a]' : 'border-l-[3px] border-l-transparent'}`}
               >
                 <div className="flex items-center gap-3">
                    <span className={`serif text-lg md:text-xl transition-colors ${selectedIndex === idx ? 'text-stone-900' : 'text-stone-600'}`}>{s.term}</span>
                 </div>
                 <span className={`text-[7px] md:text-[8px] uppercase tracking-[0.2em] font-black px-2 py-1 rounded-sm border transition-all ${
                   s.source === 'local' ? 'bg-[#7c1a1a]/5 text-[#7c1a1a] border-[#7c1a1a]/10' : 
                   s.source === 'seed' ? 'bg-stone-100 text-stone-500 border-stone-200' : 
                   'bg-stone-900 text-white border-stone-900 shadow-sm'
                 }`}>
                   {s.source === 'local' ? 'Archive' : s.source === 'seed' ? 'Scribe' : 'Global'}
                 </span>
               </button>
             ))}
          </div>
        )}
      </div>

      <div className="min-h-[40px]">
        {loading && <div className="bg-white border border-stone-100 p-8 md:p-12 animate-pulse space-y-8 rounded-sm"><div className="h-10 w-40 bg-stone-50" /></div>}
        {result && !loading && <ResultCard entry={result} />}
      </div>

      <div className="pt-12 md:pt-20 border-t border-stone-100">
        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6 mb-10">
          <div className="border-l-[2px] border-[#7c1a1a] pl-4 md:pl-6 py-0.5">
            <h2 className="text-[10px] uppercase tracking-[0.4em] text-stone-900 font-black mb-1">Archival Chronicles</h2>
            <p className="text-stone-400 text-[8px] uppercase tracking-[0.1em] font-medium">Unearthed insights</p>
          </div>
          <button onClick={() => { resumeAudioContext(); onStartArena(); }} className="group relative bg-[#7c1a1a] text-white px-6 md:px-8 py-3 flex items-center gap-3 shadow-md hover:shadow-[#7c1a1a]/20 hover:-translate-y-0.5 transition-all rounded-sm w-full sm:w-auto justify-center">
            <svg className="group-hover:rotate-12 transition-transform" xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="currentColor"><path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"/></svg>
            <span className="text-[9px] uppercase tracking-[0.4em] font-black relative z-10">Start Arena</span>
          </button>
        </div>
        <HistoryGrid history={history} onEntryClick={onEntryClick} />
      </div>
    </div>
  );
};

